1	import { useCallback, useSyncExternalStore } from "react";
2	import { Option, Schema } from "effect";
3	import { type ProviderKind, type ProviderServiceTier } from "@t3tools/contracts";
4	import { getDefaultModel, getModelOptions, normalizeModelSlug } from "@t3tools/shared/model";
5	
6	const APP_SETTINGS_STORAGE_KEY = "t3code:app-settings:v1";
7	const MAX_CUSTOM_MODEL_COUNT = 32;
8	export const MAX_CUSTOM_MODEL_LENGTH = 256;
9	export const APP_SERVICE_TIER_OPTIONS = [
10	  {
11	    value: "auto",
12	    label: "Automatic",
13	    description: "Use Codex defaults without forcing a service tier.",
14	  },
15	  {
16	    value: "fast",
17	    label: "Fast",
18	    description: "Request the fast service tier when the model supports it.",
19	  },
20	  {
21	    value: "flex",
22	    label: "Flex",
23	    description: "Request the flex service tier when the model supports it.",
24	  },
25	] as const;
26	export type AppServiceTier = (typeof APP_SERVICE_TIER_OPTIONS)[number]["value"];
27	const AppServiceTierSchema = Schema.Literals(["auto", "fast", "flex"]);
28	const MODELS_WITH_FAST_SUPPORT = new Set(["gpt-5.4"]);
29	const BUILT_IN_MODEL_SLUGS_BY_PROVIDER: Record<ProviderKind, ReadonlySet<string>> = {
30	  codex: new Set(getModelOptions("codex").map((option) => option.slug)),
31	};
32	
33	const AppSettingsSchema = Schema.Struct({
34	  codexBinaryPath: Schema.String.check(Schema.isMaxLength(4096)).pipe(
35	    Schema.withConstructorDefault(() => Option.some("")),
36	  ),
37	  codexHomePath: Schema.String.check(Schema.isMaxLength(4096)).pipe(
38	    Schema.withConstructorDefault(() => Option.some("")),
39	  ),
40	  confirmThreadDelete: Schema.Boolean.pipe(Schema.withConstructorDefault(() => Option.some(true))),
41	  enableAssistantStreaming: Schema.Boolean.pipe(
42	    Schema.withConstructorDefault(() => Option.some(false)),
43	  ),
44	  codexServiceTier: AppServiceTierSchema.pipe(Schema.withConstructorDefault(() => Option.some("auto"))),
45	  customCodexModels: Schema.Array(Schema.String).pipe(
46	    Schema.withConstructorDefault(() => Option.some([])),
47	  ),
48	});
49	export type AppSettings = typeof AppSettingsSchema.Type;
50	export interface AppModelOption {
51	  slug: string;
52	  name: string;
53	  isCustom: boolean;
54	}
55	
56	export function resolveAppServiceTier(serviceTier: AppServiceTier): ProviderServiceTier | null {
57	  return serviceTier === "auto" ? null : serviceTier;
58	}
59	
60	export function shouldShowFastTierIcon(
61	  model: string | null | undefined,
62	  serviceTier: AppServiceTier,
63	): boolean {
64	  const normalizedModel = normalizeModelSlug(model);
65	  return (
66	    resolveAppServiceTier(serviceTier) === "fast" &&
67	    normalizedModel !== null &&
68	    MODELS_WITH_FAST_SUPPORT.has(normalizedModel)
69	  );
70	}
71	
