## Step 3: `apps/web/src/hooks/useTheme.ts` — Full Replacement

The file is **fully replaced** (no JSX, stays `.ts`). Key design decisions:

### Module-level state (external store pattern, preserved from existing)

```ts
import { createContext, useContext } from "react";
import { type Theme, type ThemeId, resolveTheme, themeColorsToCssVars, DEFAULT_THEME_ID, isThemeId } from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:theme-id";

export type { ThemeId };
export type { Theme };

// ---- Module-level external store ----
let listeners: Array<() => void> = [];
let currentThemeId: ThemeId = ...;   // initialized below

function emitChange() { for (const l of listeners) l(); }

function getStoredThemeId(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  return isThemeId(raw) ? raw : DEFAULT_THEME_ID;
}
```

### Flash prevention — applied immediately on module load

```ts
function applyThemeToDOM(theme: Theme, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  // Apply all CSS vars
  const vars = themeColorsToCssVars(theme.colors);
  for (const [property, value] of Object.entries(vars)) {
    document.documentElement.style.setProperty(property, value);
  }
  // Toggle .dark class for Tailwind @variant dark (&:is(.dark, .dark *))
  document.documentElement.classList.toggle("dark", theme.isDark);
  // Update color-scheme
  document.documentElement.style.setProperty("color-scheme", theme.isDark ? "dark" : "light");
  if (suppressTransitions) {
    document.documentElement.offsetHeight; // force reflow
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Flash prevention: run immediately on module import
currentThemeId = getStoredThemeId();
applyThemeToDOM(resolveTheme(currentThemeId));
```

### React Context

```ts
interface ThemeContextValue {
  themeId: ThemeId;
  theme: Theme;
  resolvedTheme: "light" | "dark";
  setThemeId: (id: ThemeId) => void;
}

export const ThemeContext = createContext<ThemeContextValue | null>(null);

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error("useTheme must be used within ThemeProvider");
  return ctx;
}
```

The hook no longer uses `useSyncExternalStore` directly — state is managed in `ThemeProvider` via `useState`. The module-level store (`listeners`, `currentThemeId`, `emitChange`) is still used by `ThemeProvider` to handle cross-tab storage sync.

Export also: `applyThemeToDOM` and `getStoredThemeId` (needed by `ThemeProvider`).

### Cross-tab sync helper export

```ts
export function subscribeToStorageChanges(onExternalChange: (id: ThemeId) => void): () => void {
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      const id = getStoredThemeId();
      onExternalChange(id);
    }
  };
  window.addEventListener("storage", handleStorage);
  return () => window.removeEventListener("storage", handleStorage);
}
```

