## Step 4: `apps/web/src/components/ThemeProvider.tsx` — New File

```tsx
import { useState, useEffect, useCallback, type ReactNode } from "react";
import { resolveTheme, type ThemeId } from "@t3tools/shared/theme";
import {
  ThemeContext,
  applyThemeToDOM,
  getStoredThemeId,
  subscribeToStorageChanges,
} from "../hooks/useTheme";

const STORAGE_KEY = "t3code:theme-id";

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [themeId, setThemeIdState] = useState<ThemeId>(() => getStoredThemeId());
  const theme = resolveTheme(themeId);
  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const setThemeId = useCallback((id: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, id);
    setThemeIdState(id);
    applyThemeToDOM(resolveTheme(id), true);
  }, []);

  // Keep DOM in sync when state changes (handles SSR hydration edge cases)
  useEffect(() => {
    applyThemeToDOM(theme);
  }, [theme]);

  // Cross-tab storage sync
  useEffect(() => {
    return subscribeToStorageChanges((id) => {
      setThemeIdState(id);
      applyThemeToDOM(resolveTheme(id), true);
    });
  }, []);

  return (
    <ThemeContext.Provider value={{ themeId, theme, resolvedTheme, setThemeId }}>
      {children}
    </ThemeContext.Provider>
  );
}
```

Note: `STORAGE_KEY` can also be imported from `useTheme.ts` if exported there. Centralizing it in `useTheme.ts` as an export is the right approach.

