## Step 5: `apps/web/src/components/ThemeSelector.tsx` — New File

The component renders 3 theme cards side-by-side with a color swatch preview and selection indicator. It uses `useTheme()` to read and set the active theme.

### Structure

```tsx
import { useTheme } from "../hooks/useTheme";
import { THEMES, THEME_IDS, type ThemeId } from "@t3tools/shared/theme";
import { cn } from "~/lib/utils";
import { CheckIcon } from "lucide-react";

export function ThemeSelector() {
  const { themeId, setThemeId } = useTheme();

  return (
    <div
      role="radiogroup"
      aria-label="Theme"
      className="grid grid-cols-3 gap-3"
    >
      {THEME_IDS.map((id) => {
        const theme = THEMES[id];
        const selected = themeId === id;
        return (
          <ThemeCard
            key={id}
            theme={theme}
            selected={selected}
            onSelect={() => setThemeId(id)}
          />
        );
      })}
    </div>
  );
}
```

### `ThemeCard` — individual card

Each card shows:
1. A mini color swatch strip (3–4 color rects using the theme's background, primary, accent, sidebarBackground values as inline `style` background colors — NOT Tailwind classes, since these are theme-data colors not the active CSS vars)
2. The theme label
3. A "Selected" badge (same visual style as the existing radio picker in settings) or a check icon

```tsx
function ThemeCard({
  theme,
  selected,
  onSelect,
}: {
  theme: Theme;
  selected: boolean;
  onSelect: () => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={onSelect}
      className={cn(
        "group relative flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        selected
          ? "border-primary/60 bg-primary/8"
          : "border-border bg-background hover:bg-accent",
      )}
    >
      {/* Swatch preview */}
      <div
        className="relative h-14 w-full overflow-hidden rounded-lg border"
        style={{ background: theme.colors.background, borderColor: theme.colors.border }}
        aria-hidden="true"
      >
        {/* Sidebar strip */}
        <div
          className="absolute inset-y-0 left-0 w-6"
          style={{ background: theme.colors.sidebarBackground }}
        />
        {/* Main area accent blobs */}
        <div
          className="absolute bottom-2 left-8 h-2 w-10 rounded-full"
          style={{ background: theme.colors.primary }}
        />
        <div
          className="absolute right-2 top-2 h-1.5 w-8 rounded-full opacity-50"
          style={{ background: theme.colors.mutedForeground }}
        />
        <div
          className="absolute right-2 top-5 h-1.5 w-5 rounded-full opacity-30"
          style={{ background: theme.colors.mutedForeground }}
        />
        {/* Selected check */}
        {selected && (
          <div
            className="absolute right-1.5 bottom-1.5 flex size-4 items-center justify-center rounded-full"
            style={{ background: theme.colors.primary }}
          >
            <CheckIcon className="size-2.5 text-white" />
          </div>
        )}
      </div>

      {/* Label row */}
      <div className="flex items-center justify-between gap-1">
        <span className="text-xs font-medium text-foreground">{theme.label}</span>
        {selected && (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        )}
      </div>
    </button>
  );
}
```

Key: the swatch uses **inline `style`** props referencing `theme.colors.*` string values from the theme data — not Tailwind utility classes — so the previews render correctly regardless of which theme is currently active on the page.

