# Custom Theme System — T3 Code

## Context

The app currently has a minimal light/dark/system toggle in `apps/web/src/hooks/useTheme.ts` using `useSyncExternalStore`. This plan replaces it with a proper named-theme system: three built-in themes (`t3-dark`, `t3-light`, `t3-midnight`) covering all existing CSS variables plus new domain-specific ones (sidebar, editor, terminal, status bar). The `resolvedTheme: "light" | "dark"` surface is preserved so the four Shiki/diff consumers require zero changes.

---

## Files to Create

1. `packages/shared/src/theme.ts`
2. `apps/web/src/components/ThemeProvider.tsx`
3. `apps/web/src/components/ThemeSelector.tsx`

## Files to Modify

1. `packages/shared/package.json` — add `./theme` subpath export
2. `apps/web/src/hooks/useTheme.ts` — full replacement (no JSX needed, stays `.ts`)
3. `apps/web/src/index.css` — add new CSS vars to `@theme inline` and `:root`
4. `apps/web/src/routes/__root.tsx` — wrap with `ThemeProvider`
5. `apps/web/src/routes/_chat.settings.tsx` — swap in `ThemeSelector`

---

## Step 1 — `packages/shared/src/theme.ts` (new)

### Types

```ts
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

export interface ThemeColors {
  // Core (match existing :root / @variant dark vars exactly)
  background: string; foreground: string;
  card: string; cardForeground: string;
  popover: string; popoverForeground: string;
  primary: string; primaryForeground: string;
  secondary: string; secondaryForeground: string;
  muted: string; mutedForeground: string;
  accent: string; accentForeground: string;
  destructive: string; destructiveForeground: string;
  border: string; input: string; ring: string;
  info: string; infoForeground: string;
  success: string; successForeground: string;
  warning: string; warningForeground: string;
  // New domain-specific
  sidebarBackground: string; sidebarForeground: string;
  sidebarBorder: string; sidebarAccent: string;
  sidebarAccentForeground: string; sidebarRing: string;
  editorBackground: string; editorForeground: string; editorBorder: string;
  terminalBackground: string; terminalForeground: string;
  statusBarBackground: string; statusBarForeground: string;
}

export interface Theme {
  id: ThemeId;
  label: string;
  isDark: boolean;
  colors: ThemeColors;
}
```

### Utilities

```ts
// camelCase → --kebab-case CSS var name
function toKebab(key: string): string {
  return key.replace(/([A-Z])/g, (c) => `-${c.toLowerCase()}`);
}

export function themeColorsToCssVars(colors: ThemeColors): ReadonlyArray<[string, string]> {
  return Object.entries(colors).map(([k, v]) => [`--${toKebab(k)}`, v]);
}

export function isThemeId(value: unknown): value is ThemeId {
  return typeof value === "string" && value in THEMES;
