## Step 3 — `apps/web/src/hooks/useTheme.ts` (full replacement, stays `.ts`)

Key design: keeps module-level flash prevention (same as existing code). React Context is introduced here; state lives in `ThemeProvider`.

```ts
import { createContext, useContext } from "react";
import { type Theme, type ThemeId, resolveTheme, themeColorsToCssVars } from "@t3tools/shared/theme";
import { DEFAULT_THEME_ID, isThemeId } from "@t3tools/shared/theme";

export const THEME_STORAGE_KEY = "t3code:theme-id";

// ── DOM application ──────────────────────────────────────────────────────────

export function applyThemeToDOM(theme: Theme, suppressTransitions = false): void {
  if (suppressTransitions) document.documentElement.classList.add("no-transitions");
  for (const [property, value] of themeColorsToCssVars(theme.colors)) {
    document.documentElement.style.setProperty(property, value);
  }
  document.documentElement.classList.toggle("dark", theme.isDark);
  document.documentElement.style.setProperty("color-scheme", theme.isDark ? "dark" : "light");
  if (suppressTransitions) {
    // eslint-disable-next-line @typescript-eslint/no-unused-expressions
    document.documentElement.offsetHeight; // force reflow
    requestAnimationFrame(() => document.documentElement.classList.remove("no-transitions"));
  }
}

export function getStoredThemeId(): ThemeId {
  try {
    const raw = localStorage.getItem(THEME_STORAGE_KEY);
    return isThemeId(raw) ? raw : DEFAULT_THEME_ID;
  } catch {
    return DEFAULT_THEME_ID;
  }
}

export function subscribeToStorageChanges(cb: (id: ThemeId) => void): () => void {
  const handler = (e: StorageEvent) => {
    if (e.key === THEME_STORAGE_KEY) cb(getStoredThemeId());
  };
  window.addEventListener("storage", handler);
  return () => window.removeEventListener("storage", handler);
}

// ── Flash prevention — runs synchronously on first import ────────────────────
applyThemeToDOM(resolveTheme(getStoredThemeId()));

// ── React Context ────────────────────────────────────────────────────────────

export interface ThemeContextValue {
  themeId: ThemeId;
  theme: Theme;
  resolvedTheme: "light" | "dark";
  setThemeId: (id: ThemeId) => void;
}

export const ThemeContext = createContext<ThemeContextValue | null>(null);

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (ctx === null) throw new Error("useTheme must be used within ThemeProvider");
  return ctx;
}
```

**Backward compatibility:** `resolvedTheme: "light" | "dark"` is preserved in `ThemeContextValue`. All four Shiki/diff consumers only destructure `resolvedTheme` and need no changes.

