```tsx
import { CheckIcon } from "lucide-react";
import { THEMES, THEME_IDS, type Theme } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";
import { cn } from "~/lib/utils";

export function ThemeSelector() {
  const { themeId, setThemeId } = useTheme();
  return (
    <div role="radiogroup" aria-label="Theme" className="grid grid-cols-3 gap-3">
      {THEME_IDS.map((id) => (
        <ThemeCard
          key={id}
          theme={THEMES[id]}
          selected={themeId === id}
          onSelect={() => setThemeId(id)}
        />
      ))}
    </div>
  );
}

function ThemeCard({ theme, selected, onSelect }: {
  theme: Theme; selected: boolean; onSelect: () => void;
}) {
  return (
    <button
      type="button" role="radio" aria-checked={selected} onClick={onSelect}
      className={cn(
        "relative flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        selected
          ? "border-primary/60 bg-primary/8"
          : "border-border bg-background hover:bg-accent",
      )}
    >
      {/* Mini app preview swatch */}
      <div
        className="relative h-14 w-full overflow-hidden rounded-lg border"
        style={{ background: theme.colors.background, borderColor: theme.colors.border }}
        aria-hidden="true"
      >
        {/* Sidebar strip */}
        <div className="absolute inset-y-0 left-0 w-5"
          style={{ background: theme.colors.sidebarBackground }} />
        {/* Mock content lines */}
        <div className="absolute right-2 top-2.5 h-1.5 w-10 rounded-full opacity-40"
          style={{ background: theme.colors.mutedForeground }} />
        <div className="absolute right-2 top-5 h-1.5 w-7 rounded-full opacity-25"
          style={{ background: theme.colors.mutedForeground }} />
        {/* Primary accent blob */}
        <div className="absolute bottom-2.5 left-7 h-2 w-8 rounded-full"
          style={{ background: theme.colors.primary }} />
        {/* Status bar strip at bottom */}
        <div className="absolute inset-x-0 bottom-0 h-1.5"
          style={{ background: theme.colors.statusBarBackground }} />
        {/* Selected check */}
        {selected && (
          <div className="absolute right-1.5 top-1.5 flex size-4 items-center justify-center rounded-full"
            style={{ background: theme.colors.primary }}>
            <CheckIcon className="size-2.5 text-white" />
          </div>
        )}
      </div>

      {/* Label */}
      <div className="flex items-center justify-between gap-1">
        <span className="text-xs font-medium text-foreground">{theme.label}</span>
        {selected && (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        )}
      </div>
    </button>
  );
}
```

