import { createContext, useContext } from "react";
import {
  type Theme,
  type ThemeId,
  DEFAULT_THEME_ID,
  resolveTheme,
  themeColorsToCssVars,
} from "@t3tools/shared/theme";

export type { Theme, ThemeId };

const STORAGE_KEY = "t3code:theme-id";

export interface ThemeContextValue {
  themeId: ThemeId;
  theme: Theme;
  setThemeId: (id: ThemeId) => void;
  resolvedTheme: "light" | "dark";
}

export const ThemeContext = createContext<ThemeContextValue>({
  themeId: DEFAULT_THEME_ID,
  theme: resolveTheme(DEFAULT_THEME_ID),
  setThemeId: () => undefined,
  resolvedTheme: "dark",
});

export function useTheme(): ThemeContextValue {
  return useContext(ThemeContext);
}

export function getStoredThemeId(): ThemeId {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight") return raw;
  } catch {
    // localStorage unavailable (e.g. SSR, private browsing restriction)
  }
  return DEFAULT_THEME_ID;
}

export function applyThemeToDOM(theme: Theme, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const root = document.documentElement;
  const cssVars = themeColorsToCssVars(theme.colors);
  for (const [property, value] of Object.entries(cssVars)) {
    root.style.setProperty(property, value);
  }

  root.classList.toggle("dark", theme.isDark);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

export function subscribeToStorageChanges(callback: () => void): () => void {
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) callback();
  };
  window.addEventListener("storage", handleStorage);
  return () => window.removeEventListener("storage", handleStorage);
}

// Apply immediately on module load to prevent flash
applyThemeToDOM(resolveTheme(getStoredThemeId()));

