import { useCallback, useEffect, useState } from "react";
import { resolveTheme, type ThemeId } from "@t3tools/shared/theme";
import {
  ThemeContext,
  applyThemeToDOM,
  getStoredThemeId,
  subscribeToStorageChanges,
} from "../hooks/useTheme";

const STORAGE_KEY = "t3code:theme-id";

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [themeId, setThemeIdState] = useState<ThemeId>(() => getStoredThemeId());

  const theme = resolveTheme(themeId);
  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const setThemeId = useCallback((id: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, id);
    setThemeIdState(id);
    applyThemeToDOM(resolveTheme(id), true);
  }, []);

  // Keep DOM in sync when themeId changes
  useEffect(() => {
    applyThemeToDOM(theme);
  }, [theme]);

  // Cross-tab sync
  useEffect(() => {
    return subscribeToStorageChanges(() => {
      const id = getStoredThemeId();
      setThemeIdState(id);
      applyThemeToDOM(resolveTheme(id), true);
    });
  }, []);

  return (
    <ThemeContext.Provider value={{ themeId, theme, setThemeId, resolvedTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

