import { BUILT_IN_THEMES, THEME_IDS, type ThemeId } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

export function ThemeSelector() {
  const { themeId, setThemeId } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Theme selection">
      {THEME_IDS.map((id: ThemeId) => {
        const theme = BUILT_IN_THEMES[id];
        const selected = themeId === id;
        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setThemeId(id)}
            className={`flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
              selected
                ? "border-primary/60 bg-primary/8"
                : "border-border bg-background hover:bg-accent"
            }`}
          >
            {/* Mini preview swatch */}
            <div
              className="flex h-14 w-full overflow-hidden rounded-lg"
              style={{ background: theme.colors.background }}
              aria-hidden="true"
            >
              {/* Sidebar strip */}
              <div
                className="h-full w-5 shrink-0"
                style={{ background: theme.colors.sidebar }}
              />
              {/* Editor area */}
              <div className="flex flex-1 flex-col gap-0.5 p-1.5">
                {/* Simulated text lines */}
                <div
                  className="h-1 w-3/4 rounded-full opacity-60"
                  style={{ background: theme.colors.foreground }}
                />
                <div
                  className="h-1 w-1/2 rounded-full opacity-40"
                  style={{ background: theme.colors.foreground }}
                />
                <div
                  className="h-1 w-2/3 rounded-full opacity-30"
                  style={{ background: theme.colors.accent }}
                />
                {/* Status bar strip */}
                <div className="mt-auto h-1.5 w-full rounded-sm"
                  style={{ background: theme.colors.statusBar }}
                />
              </div>
              {/* Accent dot */}
              <div className="flex h-full flex-col items-end justify-start p-1">
                <div
                  className="size-2 rounded-full"
                  style={{ background: theme.colors.accent }}
                />
              </div>
            </div>

            {/* Theme name + selected badge */}
            <div className="flex items-center justify-between gap-1">
              <span
                className={`text-xs font-medium ${
                  selected ? "text-foreground" : "text-muted-foreground"
                }`}
              >
                {theme.name}
              </span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  On
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

